export interface RawOrderEvent {
  id: string;
  status: string;
  total_amount: number;
  customer_name?: string | null;
}

export interface NormalizedOrderEvent {
  id: string;
  status: "completed" | "refunded" | "failed" | "unknown";
  amount: number;
  customer_name: string;
}

export interface Logger {
  warn(message: string): void;
}

const STATUS_MAP: Record<string, NormalizedOrderEvent["status"]> = {
  PAID: "completed",
  REFUNDED: "refunded",
  FAILED: "failed",
  DECLINED: "failed",
};

export function normalizeOrderEvent(
  raw: RawOrderEvent,
  logger: Logger
): NormalizedOrderEvent {
  let status: NormalizedOrderEvent["status"];

  if (raw.status in STATUS_MAP) {
    status = STATUS_MAP[raw.status];
  } else {
    status = "unknown";
    logger.warn(
      `normalizeOrderEvent: unknown status "${raw.status}" for order id="${raw.id}"`
    );
  }

  const amount = parseFloat((raw.total_amount / 100).toFixed(2));

  const customer_name =
    raw.customer_name == null || raw.customer_name === ""
      ? "Anonymous"
      : raw.customer_name;

  return {
    id: raw.id,
    status,
    amount,
    customer_name,
  };
}

