/**
 * normalizeOrderEvent
 *
 * Normalizes a raw order event payload into a canonical NormalizedOrderEvent shape.
 *
 * Rules (derived from acceptance criteria AC1–AC6):
 *   AC1: status "PAID"              → "completed"
 *   AC2: status "REFUNDED"          → "refunded"
 *   AC3: status "FAILED"|"DECLINED" → "failed"
 *   AC4: any other status           → "unknown" + logger.warn
 *   AC5: total_amount (cents, int)  → amount (dollars, float, 2 dp)
 *   AC6: missing/null customer_name → "Anonymous"
 *
 * The function is pure except for the logger.warn call in AC4.
 * No external dependencies.
 */

export interface RawOrderEvent {
  id: string;
  status: string;
  total_amount: number;
  customer_name?: string | null;
}

export type NormalizedStatus = "completed" | "refunded" | "failed" | "unknown";

export interface NormalizedOrderEvent {
  id: string;
  status: NormalizedStatus;
  amount: number;
  customer_name: string;
}

export interface Logger {
  warn(message: string): void;
}

const STATUS_MAP: Record<string, NormalizedStatus> = {
  PAID: "completed",
  REFUNDED: "refunded",
  FAILED: "failed",
  DECLINED: "failed",
};

export function normalizeOrderEvent(
  raw: RawOrderEvent,
  logger: Logger
): NormalizedOrderEvent {
  // AC1–AC4: map status
  let status: NormalizedStatus;
  if (raw.status in STATUS_MAP) {
    status = STATUS_MAP[raw.status];
  } else {
    status = "unknown";
    logger.warn(
      `normalizeOrderEvent: unrecognized status "${raw.status}" for order id="${raw.id}"`
    );
  }

  // AC5: convert cents (integer) to dollars (float, 2 decimal places)
  const amount = parseFloat((raw.total_amount / 100).toFixed(2));

  // AC6: default missing / null customer_name to "Anonymous"
  const customer_name =
    raw.customer_name != null && raw.customer_name !== ""
      ? raw.customer_name
      : "Anonymous";

  return { id: raw.id, status, amount, customer_name };
}

